final:
module top_module(
    input [31:0] data_in,
    output [15:0] data_out
);wire [1:0] lsb = data_in[31:30];

    assign data_out = (lsb == 2'b01) ? data_in[15:0] :
                     (lsb == 2'b10) ? data_in[31:16] :
                     (lsb == 2'b11) ? ~data_in[31:16] :
                                      ~data_in[15:0];

endmodule
